// Dəyişəni istifadə edirəm
console.log(mesaj); // nəticə: undefined

// Sonra təyin edirəm
var mesaj = 'Salam dünya!';

console.log(mesaj); // nəticə: Salam dünya!

function test() {
  if (true) {
    var x = 10;
  }
  console.log(x); // nəticə: 10 - x funksiya daxilində əlçatandır
}

test();
// console.log(x); // Xəta - x funksiya xaricində əlçatan deyil

var rəng = 'qırmızı';
console.log(rəng); // nəticə: qırmızı

rəng = 'yaşıl';
console.log(rəng); // nəticə: yaşıl

var rəng = 'mavi'; // Yenidən təyin etmə
console.log(rəng); // nəticə: mavi

for (var i = 0; i < 3; i++) {
  console.log(i);
}
console.log(i); // nəticə: 3 - i döngü xaricində də əlçatandır

var ad = 'Aysel';
var ad = 'Kamran'; // Eyni dəyişəni yenidən təyin edirəm
console.log(ad); // nəticə: Kamran

// Var ilə
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Nəticə: 3, 3, 3

// Let ilə
for (let j = 0; j < 3; j++) {
  setTimeout(() => console.log(j), 100);
}
// Nəticə: 0, 1, 2

